// =============================================
// PREPARAR ARCHIVOS EXTRAIDOS DEL ZIP
// =============================================
// La DIAN exige que las facturas electrónicas se
// envíen como ZIP con un XML (la factura UBL 2.1)
// y un PDF (representación gráfica).
//
// Este nodo:
// 1. Busca los archivos .xml y .pdf en el ZIP descomprimido
// 2. Extrae el contenido XML como texto (para enviarlo al LLM)
// 3. Obtiene metadata del subject del correo (NIT, razón social, etc.)
// =============================================

const items = $input.all();
let xmlContent = null;
let xmlFileName = null;
let pdfFileName = null;
const outputItems = [];

// Obtener metadata del correo original
const emailData = $('Gmail Trigger').first().json;
const rawSubject = emailData.subject || '';

// Limpiar prefijo "Fwd:" o "Re:" para extraer la parte NIT;Empresa;...
const nitMatch = rawSubject.match(/(\d{8,10};.+)/);
const subject = nitMatch ? nitMatch[1] : rawSubject;
const subjectParts = subject.split(';');

const metadata = {
  nit_emisor: subjectParts[0] || '',
  razon_social_emisor: subjectParts[1] || '',
  referencia_documento: subjectParts[2] || '',
  tipo_documento: subjectParts[3] || '',
  email_subject: rawSubject,
  email_from: emailData.from || '',
  email_date: emailData.date || ''
};

// Recorrer todos los archivos extraidos del ZIP
for (const item of items) {
  const binaryKeys = Object.keys(item.binary || {});

  for (const key of binaryKeys) {
    const binaryData = item.binary[key];
    const fileName = binaryData.fileName || '';

    if (fileName.toLowerCase().endsWith('.xml')) {
      xmlFileName = fileName;
      // Convertir el binario a texto UTF-8 para poder leer el XML
      const buffer = Buffer.from(binaryData.data, 'base64');
      xmlContent = buffer.toString('utf-8');

      outputItems.push({
        json: { fileType: 'xml', fileName, xmlContent, ...metadata },
        binary: { data: binaryData }
      });
    } else if (fileName.toLowerCase().endsWith('.pdf')) {
      pdfFileName = fileName;
      outputItems.push({
        json: { fileType: 'pdf', fileName, ...metadata },
        binary: { data: binaryData }
      });
    }
  }
}

if (outputItems.length === 0) {
  return [{ json: { error: 'No se encontraron archivos XML o PDF en el ZIP' } }];
}

return outputItems;

// =============================================
// COMBINAR DATOS PARA EL LLM
// =============================================
// Después de subir los archivos a Google Drive,
// este nodo:
// 1. Recupera los links de Drive (para guardarlos en Sheets)
// 2. Recupera el contenido XML (para enviárselo a Claude)
// 3. Lo trunca a 100K chars si es demasiado largo
// =============================================

const driveResults = $input.all();
const prepareNode = $('Preparar Archivos').all();

// Obtener links de Google Drive
let pdfLink = '';
let xmlLink = '';

for (const result of driveResults) {
  const name = result.json.name || '';
  if (name.toLowerCase().endsWith('.pdf')) {
    pdfLink = result.json.webViewLink || 'https://drive.google.com/file/d/' + result.json.id + '/view';
  } else if (name.toLowerCase().endsWith('.xml')) {
    xmlLink = result.json.webViewLink || 'https://drive.google.com/file/d/' + result.json.id + '/view';
  }
}

// Recuperar el contenido XML y metadata
let xmlContent = '';
let metadata = {};

for (const item of prepareNode) {
  if (item.json.xmlContent) xmlContent = item.json.xmlContent;
  if (item.json.nit_emisor) {
    metadata = {
      nit_emisor: item.json.nit_emisor,
      razon_social_emisor: item.json.razon_social_emisor,
      referencia_documento: item.json.referencia_documento,
      email_from: item.json.email_from,
      email_date: item.json.email_date
    };
  }
}

// Truncar XML si excede el límite del LLM
const maxLen = 100000;
const xmlForLlm = xmlContent.length > maxLen
  ? xmlContent.substring(0, maxLen) + '\n<!-- TRUNCADO -->'
  : xmlContent;

return [{
  json: { xmlContent: xmlForLlm, pdfLink, xmlLink, ...metadata }
}];

// =============================================
// PARSEAR RESPUESTA DE CLAUDE
// =============================================
// Claude nos devuelve un JSON con los datos de la factura
// pero como string. Este nodo:
// 1. Limpia la respuesta (quita markdown si hay)
// 2. Parsea el JSON
// 3. Construye la fila final para Google Sheets
// =============================================

const llmResponse = $input.first().json;
const prevData = $('Combinar Datos').first().json;

// Obtener el texto de la respuesta del LLM
let responseText = llmResponse.text || llmResponse.response || llmResponse.output || JSON.stringify(llmResponse);

// Limpiar posible wrapping de markdown (```json ... ```)
responseText = responseText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let facturaData = {};
try {
  facturaData = JSON.parse(responseText);
} catch (e) {
  // Si falla, intentar extraer el JSON del texto
  const jsonMatch = responseText.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      facturaData = JSON.parse(jsonMatch[0]);
    } catch (e2) {
      return [{ json: { error: 'No se pudo parsear la respuesta del LLM', raw: responseText } }];
    }
  } else {
    return [{ json: { error: 'No se encontró JSON en la respuesta', raw: responseText } }];
  }
}

// Construir la fila para Google Sheets
return [{ json: {
  fecha_procesamiento: new Date().toISOString(),
  numero_factura: facturaData.numero_factura || '',
  fecha_emision: facturaData.fecha_emision || '',
  razon_social_proveedor: facturaData.razon_social_proveedor || '',
  nit_proveedor: facturaData.nit_proveedor || '',
  dv_proveedor: facturaData.dv_proveedor || '',
  razon_social_cliente: facturaData.razon_social_cliente || '',
  nit_cliente: facturaData.nit_cliente || '',
  subtotal: facturaData.subtotal || 0,
  total_iva: facturaData.total_iva || 0,
  total_factura: facturaData.total_factura || 0,
  moneda: facturaData.moneda || 'COP',
  cufe: facturaData.cufe || '',
  condicion_pago: facturaData.condicion_pago || '',
  forma_pago: facturaData.forma_pago || '',
  link_pdf: prevData.pdfLink || '',
  link_xml: prevData.xmlLink || '',
  email_origen: prevData.email_from || '',
  fecha_email: prevData.email_date || '',
  referencia: prevData.referencia_documento || ''
} }];
